# Scratch: "જો તો" બ્લોક જેવું જ
હવામાન = input("આજે હવામાન કેવું છે? (તડકો/વરસાદ): ")
if હવામાન == "તડકો":
    print("બહાર રમવા જઈએ!")
else:
    print("પ્રોગ્રામિંગ કરીએ!")

# Scratch: "જો તો નહીંતર જો તો" બ્લોક જેવું જ
કલાક = int(input("અત્યારે કેટલા વાગ્યા? (0-23): "))
if કલાક < 10:
    print("સુપ્રભાત!")
elif કલાક < 17:
    print("નમસ્કાર!")
else:
    print("શુભ સાંજ!")

